                    graph[node].forEach((target, index) => {
                        if (index > 0) {
                            const comma = document.createElement('span');
                            comma.textContent = ', ';
                            edgesElement.appendChild(comma);
                        }

                        const edge = document.createElement('span');
                        edge.className = 'edge';
                        edge.textContent = '→';
                        edgesElement.appendChild(edge);

                        const targetNode = document.createElement('span');
                        targetNode.className = 'node';
                        targetNode.textContent = target;
                        edgesElement.appendChild(targetNode);
                    });

                    graphDisplay.appendChild(edgesElement);
                }

                graphDisplay.appendChild(document.createElement('br'));
            }
        }

